'    background-position: center !important;',
'    background-attachment: fixed !important;',
'    background-repeat: no-repeat !important;',
'    height: 100vh !important;',
'    margin: 0 !important;',
'    overflow: hidden !important; /* Impede que a tela "sambe" para os lados */',
'}',
'',
'/* 2. O SEGREDO DO ENCAIXE: ZERAR O CONTAINER PAI */',
'.t-Login-container {',
'    width: 100% !important;',
'    max-width: 100vw !important;',
'    padding: 20px !important; /* Margem de respiro nas bordas do celular */',
'    margin: 0 !important;',
'    display: flex !important;',
'    justify-content: center !important;',
'    align-items: center !important;',
'    min-height: 100vh !important;',
'}',
'',
'/* 3. O QUADRADO DE VIDRO (AGORA ENCAIXADO) */',
'.t-Login-region {',
'    background: radial-gradient(circle, rgba(255, 255, 255, 0.25) 0%, rgba(255, 255, 255, 0.05) 100%) !important;',
'    backdrop-filter: blur(18px) !important;',
'    -webkit-backdrop-filter: blur(18px) !important;',
'    border: 1px solid rgba(255, 255, 255, 0.3) !important;',
'    border-radius: 30px !important;',
'    box-shadow: 0 25px 50px rgba(0, 0, 0, 0.3) !important;',
