'    margin: 0 !important; /* Remove qualquer margem que tira do centro */',
'    padding: 35px 25px !important;',
'}',
'',
unistr('/* 4. T\00CDTULO E BOT\00C3O (ADAPTADOS) */'),
'.t-Login-title {',
'    font-family: ''Inter'', sans-serif !important;',
'    font-size: 1.8rem !important;',
