'    margin-bottom: 25px !important;',
'    letter-spacing: 1px;',
'}',
'',
'.t-Button--hot {',
'    width: 100% !important;',
'    background-color: #00d4ff !important;',
'    border-radius: 12px !important;',
'    height: 50px !important;',
'    font-weight: 800 !important;',
'}',
'',
